<template>
    <div class="table">
        <div class="container">
            <div class="handle-box">
                <el-input
                    v-model="selectWord"
                    placeholder="请输入歌手名"
                    class="handle-input"
                ></el-input>
                <br /><br />
                <el-button type="danger" style="font-size: 18px" @click="delAll">
                    批量删除
                </el-button>
                <el-button
                    type="success"
                    style="font-size: 18px"
                    @click="centerDialogVisible = true"
                >
                    添加歌手
                </el-button>
            </div>
        </div>

        <el-table
            ref="multipleTable"
            border
            style="width: 100%"
            height="680px"
            :data="data"
            @selection-change="handleSelectionChange"
        >
            <el-table-column type="selection" width="40"></el-table-column>

            <el-table-column label="歌手图片" width="140" align="center">
                <template slot-scope="scope">
                    <div class="singer-img">
                        <img :src="getUrl(scope.row.pic)" style="width: 100%" />
                    </div>
                    <el-upload
                        :action="uploadUrl(scope.row.id)"
                        :before-upload="beforeAvatorUpload"
                        :on-success="handleAvatorSuccess"
                    >
                        <el-button type="success" style="font-size: 16px">
                            更换
                        </el-button>
                    </el-upload>
                </template>
            </el-table-column>

            <el-table-column prop="name" label="歌手" width="120" align="center"></el-table-column>

            <el-table-column label="性别" width="60" align="center">
                <template slot-scope="scope">
                    {{ changeSex(scope.row.sex) }}
                </template>
            </el-table-column>

            <el-table-column label="生日" width="120" align="center">
                <template slot-scope="scope">
                    {{ attachBirth(scope.row.birth) }}
                </template>
            </el-table-column>

            <el-table-column prop="location" label="地区" width="120" align="center"></el-table-column>

            <el-table-column label="简介">
                <template slot-scope="scope">
                    <p style="height: 100px; overflow: auto">{{ scope.row.introduction }}</p>
                </template>
            </el-table-column>

            <el-table-column label="操作" width="360" fixed="right" align="center">
                <template slot-scope="scope">
                    <el-button
                        style="font-size: 16px"
                        type="warning"
                        @click="songEdit(scope.row.id, scope.row.name)"
                    >
                        歌曲管理
                    </el-button>
                    <el-button style="font-size: 16px" type="success" @click="handleEdit(scope.row)">
                        编辑
                    </el-button>
                    <el-button style="font-size: 16px" type="danger" @click="handleDelete(scope.row.id)">
                        删除
                    </el-button>
                </template>
            </el-table-column>
        </el-table>

        <div class="pagination">
            <el-pagination
                background
                layout="total,prev,pager,next"
                :current-page="currentPage"
                :page-size="pageSize"
                :total="tableData.length"
                @current-change="handleCurrentChange"
            ></el-pagination>
        </div>

        <el-dialog title="添加歌手" :visible.sync="centerDialogVisible" width="420px" center>
            <el-form :model="registerForm" ref="registerForm" label-width="90px">
                <el-form-item label="歌手名" size="mini">
                    <el-input v-model="registerForm.name" placeholder="请输入歌手名"></el-input>
                </el-form-item>
                <el-form-item label="性别" size="mini">
                    <el-radio-group v-model="registerForm.sex">
                        <el-radio :label="0">女</el-radio>
                        <el-radio :label="1">男</el-radio>
                        <el-radio :label="2">组合</el-radio>
                        <el-radio :label="3">不明</el-radio>
                    </el-radio-group>
                </el-form-item>
                <el-form-item label="生日" size="mini">
                    <el-date-picker
                        type="date"
                        placeholder="选择日期"
                        v-model="registerForm.birth"
                        style="width: 100%"
                    ></el-date-picker>
                </el-form-item>
                <el-form-item label="地区" size="mini">
                    <el-input v-model="registerForm.location" placeholder="请输入地区"></el-input>
                </el-form-item>
                <el-form-item label="简介" size="mini">
                    <el-input
                        v-model="registerForm.introduction"
                        placeholder="请输入简介"
                        type="textarea"
                    ></el-input>
                </el-form-item>
            </el-form>
            <span slot="footer">
                <el-button size="mini" @click="centerDialogVisible = false">取消</el-button>
                <el-button size="mini" type="primary" @click="addSinger">确定</el-button>
            </span>
        </el-dialog>

        <el-dialog title="编辑歌手" :visible.sync="editVisible" width="420px" center>
            <el-form :model="form" ref="form" label-width="90px">
                <el-form-item label="歌手名" size="mini">
                    <el-input v-model="form.name" placeholder="请输入歌手名"></el-input>
                </el-form-item>
                <el-form-item label="性别" size="mini">
                    <el-radio-group v-model="form.sex">
                        <el-radio :label="0">女</el-radio>
                        <el-radio :label="1">男</el-radio>
                        <el-radio :label="2">组合</el-radio>
                        <el-radio :label="3">不明</el-radio>
                    </el-radio-group>
                </el-form-item>
                <el-form-item label="生日" size="mini">
                    <el-date-picker
                        type="date"
                        placeholder="选择日期"
                        v-model="form.birth"
                        style="width: 100%"
                    ></el-date-picker>
                </el-form-item>
                <el-form-item label="地区" size="mini">
                    <el-input v-model="form.location" placeholder="请输入地区"></el-input>
                </el-form-item>
                <el-form-item label="简介" size="mini">
                    <el-input
                        v-model="form.introduction"
                        placeholder="请输入简介"
                        type="textarea"
                    ></el-input>
                </el-form-item>
            </el-form>
            <span slot="footer">
                <el-button size="mini" @click="editVisible = false">取消</el-button>
                <el-button size="mini" type="primary" @click="editSave">确定</el-button>
            </span>
        </el-dialog>

        <el-dialog title="删除歌手" :visible.sync="delVisible" width="320px" center>
            <div align="center">删除不可恢复，确认删除吗？</div>
            <span slot="footer">
                <el-button size="mini" @click="delVisible = false">取消</el-button>
                <el-button size="mini" type="primary" @click="deleteRow">确定</el-button>
            </span>
        </el-dialog>
    </div>
</template>

<script>
import { setSinger, getAllSinger, updateSinger, delSinger } from "../api/index";
import { mixin } from "../mixins/index";

export default {
    mixins: [mixin],
    data() {
        return {
            centerDialogVisible: false,
            editVisible: false,
            delVisible: false,
            registerForm: {
                name: "",
                sex: 1,
                birth: null,
                location: "",
                introduction: "",
            },
            form: {
                id: "",
                name: "",
                sex: 1,
                birth: null,
                location: "",
                introduction: "",
            },
            tableData: [],
            tempData: [],
            selectWord: "",
            pageSize: 5,
            currentPage: 1,
            idx: -1,
            multipleSelection: [],
        };
    },
    computed: {
        data() {
            return this.tableData.slice(
                (this.currentPage - 1) * this.pageSize,
                this.currentPage * this.pageSize
            );
        },
    },
    watch: {
        selectWord() {
            if (!this.selectWord) {
                this.tableData = this.tempData;
                return;
            }
            this.tableData = this.tempData.filter((item) =>
                (item.name || "").includes(this.selectWord)
            );
            this.currentPage = 1;
        },
    },
    created() {
        this.getData();
    },
    methods: {
        handleCurrentChange(val) {
            this.currentPage = val;
        },
        getData() {
            getAllSinger().then((res) => {
                const list = Array.isArray(res) ? res : [];
                this.tempData = list;
                this.tableData = list;
                this.currentPage = 1;
            });
        },
        formatDate(val) {
            const d = val ? new Date(val) : new Date();
            const y = d.getFullYear();
            const m = `${d.getMonth() + 1}`.padStart(2, "0");
            const day = `${d.getDate()}`.padStart(2, "0");
            return `${y}-${m}-${day}`;
        },
        resetRegisterForm() {
            this.registerForm = {
                name: "",
                sex: 1,
                birth: null,
                location: "",
                introduction: "",
            };
        },
        addSinger() {
            const name = (this.registerForm.name || "").trim();
            if (!name) {
                this.notify("请输入歌手名", "error");
                return;
            }
            const payload = {
                name,
                sex: this.registerForm.sex,
                pic: "/img/user.jpg",
                birth: this.formatDate(this.registerForm.birth),
                location: this.registerForm.location || "",
                introduction: this.registerForm.introduction || "",
            };
            setSinger(payload)
                .then((res) => {
                    if (res && res.code == 1) {
                        this.notify("添加成功", "success");
                        this.centerDialogVisible = false;
                        this.resetRegisterForm();
                        this.getData();
                    } else {
                        this.notify((res && res.msg) || "添加失败", "error");
                    }
                })
                .catch(() => {
                    this.notify("添加失败", "error");
                });
        },
        handleEdit(row) {
            this.editVisible = true;
            this.form = {
                id: row.id,
                name: row.name || "",
                sex: row.sex,
                birth: row.birth,
                location: row.location || "",
                introduction: row.introduction || "",
            };
        },
        editSave() {
            const name = (this.form.name || "").trim();
            if (!name) {
                this.notify("请输入歌手名", "error");
                return;
            }
            const payload = {
                id: this.form.id,
                name,
                sex: this.form.sex,
                birth: this.formatDate(this.form.birth),
                location: this.form.location || "",
                introduction: this.form.introduction || "",
            };
            updateSinger(payload)
                .then((res) => {
                    if (res && res.code == 1) {
                        this.notify("修改成功", "success");
                        this.editVisible = false;
                        this.getData();
                    } else {
                        this.notify((res && res.msg) || "修改失败", "error");
                    }
                })
                .catch(() => {
                    this.notify("修改失败", "error");
                });
        },
        uploadUrl(id) {
            return `${this.$store.state.HOST}/singer/updateSingerPic?id=${id}`;
        },
        deleteRow() {
            delSinger(this.idx)
                .then((res) => {
                    if (res) {
                        this.notify("删除成功", "success");
                        this.getData();
                    } else {
                        this.notify("删除失败", "error");
                    }
                })
                .catch(() => {
                    this.notify("删除失败", "error");
                });
            this.delVisible = false;
        },
        songEdit(id, name) {
            this.$router.push({ path: "/Song", query: { id, name } });
        },
    },
};
</script>

<style scoped>
.handle-box {
    margin-bottom: 20px;
    padding: 16px 18px;
    background: linear-gradient(135deg, rgba(14, 165, 233, 0.08), rgba(255, 255, 255, 0.95));
    border: 1px solid rgba(148, 163, 184, 0.25);
    border-radius: 14px;
    box-shadow: 0 10px 24px rgba(15, 23, 42, 0.08);
}

.singer-img {
    width: 100%;
    height: 120px;
    border-radius: 10px;
    margin-bottom: 6px;
    overflow: hidden;
    border: 1px solid rgba(148, 163, 184, 0.25);
    background: #f8fafc;
}

.handle-input {
    width: 320px;
    display: inline-block;
}

.pagination {
    display: flex;
    justify-content: center;
    margin-top: 16px;
}
</style>



